        await File.WriteAllTextAsync(Path.Combine(root, "matchdir", "matchfile.txt"), "x");
        // A non-matching sibling ensures the matcher is selective.
        await File.WriteAllTextAsync(Path.Combine(root, "other.txt"), "x");

