        Assert.Equal(2, result.Results.Count);
        Assert.Contains(result.Results, r => r.Name == "matchdir" && r.IsDirectory);
        Assert.Contains(result.Results, r => r.Path == "matchdir/matchfile.txt" && !r.IsDirectory);
